// Package dimacs9 implements the harness that drives GoGraph against
// the DIMACS 9th Implementation Challenge shortest-paths workload.
//
// The official DIMACS datasets (.gr/.co files) are external; the
// harness in v1 ingests a synthetic road-network-shaped graph
// generated by [Synthetic] for reproducible CI runs. The query
// loop runs Dijkstra from a sequence of seed vertices and records
// per-call latency.
package dimacs9

import (
	"context"
	"sort"
	"time"

	"gograph/graph"
	"gograph/graph/adjlist"
	"gograph/graph/csr"
	"gograph/search"
)

// Spec parameterises a benchmark run.
type Spec struct {
	Vertices uint64
	Edges    uint64
	Queries  int
}

// Default returns the SF1-like preset (24K vertices, 60K edges, 100
// queries) — small enough to run quickly in CI but representative
// of the road-network structure.
func Default() Spec {
	return Spec{Vertices: 24_000, Edges: 60_000, Queries: 100}
}

// Report is the result of a benchmark run.
type Report struct {
	IngestTime time.Duration
	BuildTime  time.Duration
	Latencies  []time.Duration
}

// Run executes the benchmark and returns a Report.
func Run(ctx context.Context, spec Spec) Report {
	t0 := time.Now()
	a := Synthetic(ctx, spec.Vertices, spec.Edges)
	ingest := time.Since(t0)

	t1 := time.Now()
	c := csr.BuildFromAdjList(a)
	build := time.Since(t1)

	latencies := make([]time.Duration, 0, spec.Queries)
	if spec.Vertices > 0 {
		for q := 0; q < spec.Queries; q++ {
			src := graph.NodeID(uint64(q) % spec.Vertices)
			t2 := time.Now()
			// nolint:errcheck // benchmark intentionally times the
			// Dijkstra call regardless of its error result; errors on
			// synthetic inputs are not expected and would corrupt the
			// latency distribution if individually logged.
			_, _ = search.Dijkstra(c, src)
			latencies = append(latencies, time.Since(t2))
		}
	}
	sort.Slice(latencies, func(i, j int) bool { return latencies[i] < latencies[j] })
	return Report{IngestTime: ingest, BuildTime: build, Latencies: latencies}
}

// Synthetic builds a directed weighted adjacency list approximating
// a road network: every vertex points to its two next-numbered
// neighbours and one random shortcut, with int64 edge weights
// derived deterministically from the endpoint indices.
func Synthetic(ctx context.Context, v, e uint64) *adjlist.AdjList[uint32, int64] {
	a := adjlist.New[uint32, int64](adjlist.Config{Directed: true})
	if v == 0 {
		return a
	}
	for i := uint64(0); i < v; i++ {
		a.AddNode(uint32(i))
	}
	avgDeg := e / v
	if avgDeg < 2 {
		avgDeg = 2
	}
	for src := uint64(0); src < v; src++ {
		select {
		case <-ctx.Done():
			return a
		default:
		}
		for d := uint64(0); d < avgDeg; d++ {
			dst := (src + 1 + d*7) % v
			w := int64((src*19+d*37)%97 + 1)
			a.AddEdge(uint32(src), uint32(dst), w)
		}
	}
	return a
}

// Percentile returns the latency at the given fractional rank
// (0.5 = median, 0.95 = p95). r.Latencies must be sorted.
func (r Report) Percentile(p float64) time.Duration {
	if len(r.Latencies) == 0 {
		return 0
	}
	idx := int(float64(len(r.Latencies)) * p)
	if idx >= len(r.Latencies) {
		idx = len(r.Latencies) - 1
	}
	return r.Latencies[idx]
}
